            //
            aOrbiterH = ((aOrbiterH + aOrbiterG) + 4278464365761703908U) + aOrbiterUpdateSaltC[(((31U - aIndex) + 14U)) & S_SALT1];
            aOrbiterB = (aOrbiterB ^ aOrbiterH) ^ 983763278825975270U;
            aOrbiterB = RotL64((aOrbiterB * 9562462640564796653U), 11U);
            //
