            //
            aOrbiterD = ((aOrbiterD + aOrbiterJ) + 2856413455199585193U) + aNonceWordO;
            aOrbiterH = ((aOrbiterH ^ aOrbiterD) ^ 14350542551546147117U) ^ aOrbiterUpdateSaltD[((aIndex + 8U)) & S_SALT1];
