            //
            aWandererC = aWandererC ^ (((RotL64(aScatter, 39U) + RotL64(aOrbiterD, 51U)) + aOrbiterF) + aWandererUpdateSaltA[(((31U - aIndex) + 27U)) & S_SALT1]);
            aWandererJ = aWandererJ + ((RotL64(aCross, 11U) + RotL64(aOrbiterA, 44U)) + aOrbiterD);
