            aOrbiterJ = ((aWandererK + RotL64(aCross, 29U)) + 9035707244562680967U) + aOrbiterAssignSaltE[(((31U - aIndex) + 9U)) & S_SALT1];
            aOrbiterI = ((aWandererE + RotL64(aScatter, 11U)) + 10316640723388106957U) + aNonceWordF;
            aOrbiterK = ((aWandererB + RotL64(aPrevious, 47U)) + RotL64(aCarry, 3U)) + 10635521641510410175U;
            aOrbiterG = (aWandererJ + RotL64(aIngress, 13U)) + 11763124451382819992U;
            aOrbiterA = (aWandererA + RotL64(aPrevious, 43U)) + 12062767026404621546U;
