            aOrbiterI = ((aOrbiterI + aOrbiterK) + 3973823791790209199U) + aNonceWordB;
            aOrbiterC = (aOrbiterC ^ aOrbiterI) ^ 3678258581830318748U;
            aOrbiterC = RotL64((aOrbiterC * 12323224507866950119U), 35U);
            //
            aOrbiterE = ((aOrbiterE + aOrbiterJ) + 6888143268783274965U) + aOrbiterUpdateSaltC[(((31U - aIndex) + 6U)) & S_SALT1];
            aOrbiterG = ((aOrbiterG ^ aOrbiterE) ^ 4927554738613467593U) ^ aNonceWordM;
            aOrbiterG = RotL64((aOrbiterG * 9936339028359146277U), 51U);
            //
            aOrbiterK = ((aOrbiterK + aOrbiterD) + 4279271375532954805U) + aNonceWordA;
            aOrbiterA = (aOrbiterA ^ aOrbiterK) ^ 6619503588861876101U;
            aOrbiterA = RotL64((aOrbiterA * 12191393329504123985U), 19U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterG) + 11705258833549243997U;
